import React, { useEffect, useState, useCallback, useMemo } from 'react';
import api from '../api/axiosConfig';
import { useTheme } from '../context/ThemeContext';
import ReactMarkdown from 'react-markdown';
import { Trash2, Download, Archive, Calendar, ShieldCheck, Eye, X, BarChart3, AlignLeft } from 'lucide-react';
import toast from 'react-hot-toast';

const VaultPage = () => {
  const { isDark } = useTheme();
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedItem, setSelectedItem] = useState(null);

  /* ───────── 1. API Actions (Systematic) ───────── */
  const fetchHistory = useCallback(async () => {
    try {
      const res = await api.get('/portfolio/history');
      const data = Array.isArray(res.data) ? res.data : (res.data?.data || []);
      setHistory(data);
    } catch (err) {
      toast.error("VAULT_SYNC_FAILURE: UNABLE_TO_REACH_DATABASE");
    } finally {
      setLoading(false);
    }
  }, []);

  const handleDelete = async (id) => {
    if (!window.confirm("PERMANENT_WIPE: Delete this strategy?")) return;
    try {
      await api.delete(`/portfolio/${id}`);
      setHistory(prev => prev.filter(item => item.id !== id));
      toast.success("DATA_PURGED");
    } catch (err) {
      toast.error("PURGE_ERROR: DB_LOCK_ACTIVE");
    }
  };

  const handleDownload = async (item) => {
    try {
      const response = await api.post('/portfolio/export', item, { responseType: 'blob' });
      const url = window.URL.createObjectURL(new Blob([response.data]));
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', `Strategy_Node_${item.id}.pdf`);
      document.body.appendChild(link);
      link.click();
      link.remove();
    } catch (err) {
      toast.error("EXPORT_FAILED");
    }
  };

  useEffect(() => {
    fetchHistory();
  }, [fetchHistory]);

  /* ───────── 2. OLED Theme Mapping ───────── */
  const theme = useMemo(() => ({
    bg: isDark ? '#000000' : '#ffffff',
    card: isDark ? '#000000' : '#fcfcfc',
    text: isDark ? '#ffffff' : '#000000',
    border: isDark ? '#1a1a1a' : '#e5e7eb',
    overlay: isDark ? 'rgba(0, 0, 0, 0.96)' : 'rgba(255, 255, 255, 0.92)',
    muted: isDark ? '#888' : '#666'
  }), [isDark]);

  if (loading) return <div style={{...centerStyle, color: 'var(--accent-primary)'}}>SYNCHRONIZING_CORE_VAULT...</div>;

  return (
    <div className="reveal-node" style={{...containerStyle, background: theme.bg, color: theme.text}}>
      {/* ── Page Header ── */}
      <div style={{...headerRow, borderBottom: `1px solid ${theme.border}`}}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
          <Archive size={24} color="var(--accent-primary)"/>
          <h2 style={{ fontSize: '1.4rem', fontWeight: 800, margin: 0, color: theme.text }}>STRATEGY_VAULT</h2>
        </div>
        <span style={{...vaultBadge, borderColor: 'var(--accent-primary)'}}>{history.length} NODES_STORED</span>
      </div>

      {/* ── Strategy Grid ── */}
      <div style={listStyle}>
        {history.length === 0 ? (
          <div style={{...emptyStyle, border: `1px dashed ${theme.border}`}}>NO_DATA_FOUND: INITIALIZE_STRATEGY</div>
        ) : (
          history.map((item) => (
            <div key={item.id} className="vault-card" style={{...cardStyle, background: theme.card, border: `1px solid ${theme.border}`}}>
              <div style={{ flex: 1 }}>
                <div style={tagRow}>
                  <span style={{ fontSize: '0.8rem', color: theme.muted, display: 'flex', alignItems: 'center', gap: '6px' }}>
                    <Calendar size={14}/> {new Date(item.created_at).toLocaleDateString()}
                  </span>
                  <span style={{ fontSize: '0.8rem', color: 'var(--accent-primary)', fontWeight: 800, display: 'flex', alignItems: 'center', gap: '6px' }}>
                    <ShieldCheck size={14}/> RISK: {item.risk_score}
                  </span>
                </div>
                <h4 style={{ margin: '0 0 10px 0', fontSize: '1.2rem', fontWeight: 700, color: theme.text }}>{item.goal}</h4>
              </div>

              <div style={{...actionColumn, borderLeft: `1px solid ${theme.border}`}}>
                <button onClick={() => setSelectedItem(item)} style={iconBtn} title="View"><Eye size={20}/></button>
                <button onClick={() => handleDownload(item)} style={iconBtn} title="Export"><Download size={20}/></button>
                <button onClick={() => handleDelete(item.id)} style={deleteBtn} title="Delete"><Trash2 size={20}/></button>
              </div>
            </div>
          ))
        )}
      </div>

      {/* ── OLED Description Modal ── */}
      {selectedItem && (
        <div style={{...modalOverlay, background: theme.overlay}}>
          <div style={{...modalContent, background: theme.bg, border: `2px solid var(--accent-primary)`}}>
            <div style={{...modalHeader, background: isDark ? '#000000' : '#f5f5f5', borderBottom: `1px solid ${theme.border}`}}>
              <span style={{ color: 'var(--accent-primary)', fontWeight: 800, fontSize: '0.8rem', fontFamily: 'monospace' }}>NODE_DATA // ID_{selectedItem.id}</span>
              <button onClick={() => setSelectedItem(null)} style={{background: 'none', border: 'none', color: theme.text, cursor: 'pointer'}}><X size={24}/></button>
            </div>
            <div style={modalBody}>
              <h3 style={{ color: theme.text, fontSize: '1.6rem', fontWeight: 900, marginBottom: '2rem' }}>{selectedItem.goal}</h3>
              <div className={isDark ? "markdown-dark" : "markdown-light"}>
                <p style={labelSmall}><AlignLeft size={14}/> STRATEGIC_SUMMARY</p>
                <div style={{...widgetBox, background: theme.bg, border: `1px solid ${theme.border}`}}>
                  <ReactMarkdown>{selectedItem.summary}</ReactMarkdown>
                </div>
                <p style={labelSmall}><AlignLeft size={14}/> AGENTIC_RATIONALE</p>
                <div style={{...widgetBox, background: theme.bg, border: `1px solid ${theme.border}`}}>
                  <ReactMarkdown>{selectedItem.rationale}</ReactMarkdown>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      <style>{`
        .markdown-dark p { color: #ffffff !important; line-height: 1.6; font-size: 0.95rem; }
        .markdown-light p { color: #000000 !important; line-height: 1.6; font-size: 0.95rem; }
        .vault-card:hover { border-color: var(--accent-primary) !important; transform: translateY(-2px); }
        .reveal-node { animation: fadeIn 0.4s ease-out; }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
      `}</style>
    </div>
  );
};

